import React from 'react';

interface Order {
  id: string;
  customerName: string;
  date: string;
  status: string;
  total: number;
}

const OrderCard = ({ order, onSelect }: { order: Order; onSelect: (id: string) => void }) => {
  const statusColors: Record<string, string> = {
    pending: 'bg-yellow-500',
    shipped: 'bg-blue-500',
    completed: 'bg-green-500',
  };

  return (
    <div
      className="group relative bg-gray-800/60 border border-gray-700/50 rounded-2xl p-6 cursor-pointer hover:border-indigo-500/50 hover:bg-gray-800 transition-all duration-200"
      onClick={() => onSelect(order.id)}
    >
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-white font-medium">Order #{order.id}</h3>
        <span className={`text-xs px-2 py-0.5 rounded-full ${statusColors[order.status]} text-white`}>{order.status}</span>
      </div>
      <p className="text-gray-400 text-sm">Customer: {order.customerName}</p>
      <p className="text-gray-400 text-sm">Date: {order.date}</p>
      <p className="text-gray-400 text-sm">Total: ${order.total.toFixed(2)}</p>
    </div>
  );
};

export default OrderCard;

