import React from 'react';

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
}

const UserList = ({ users, onMessage }: { users: User[]; onMessage: (id: string) => void }) => {
  return (
    <section className="py-16 bg-gray-900">
      <div className="max-w-6xl mx-auto px-4">
        <h2 className="text-2xl font-semibold text-white mb-2">Customer Management</h2>
        <p className="text-gray-400 mb-10">Manage your customer profiles and interactions.</p>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
          {users.map(user => (
            <div
              key={user.id}
              className="group relative bg-gray-800/60 border border-gray-700/50 rounded-2xl p-6 hover:border-indigo-500/50 hover:bg-gray-800 transition-all duration-200"
            >
              <h3 className="text-white font-medium mb-1">{user.name}</h3>
              <p className="text-gray-400 text-sm">Email: {user.email}</p>
              <p className="text-gray-400 text-sm">Role: {user.role}</p>
              <button
                onClick={() => onMessage(user.id)}
                className="mt-4 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
              >
                Send Message
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default UserList;
